interface CacheAdapter {
  get(key: string): Promise<string | null>;
  set(key: string, value: string, ttlSeconds: number): Promise<void>;
  delete(key: string): Promise<void>;
}

import { memoryCache } from "@hushkey/howl/api/cache";

defineConfig({
  cache: memoryCache({ maxSize: 1000 }), // evicts LRU when full
});

import { redisCache } from "@hushkey/howl/api/cache";
import { Redis } from "ioredis";

const redis = new Redis(Deno.env.get("REDIS_URL"));

defineConfig({
  cache: redisCache(redis),
  rateLimitCache: redisCache(redis), // same client, different key prefix
});

import { kvCache } from "@hushkey/howl/api/cache";

const kv = await Deno.openKv();

defineConfig({
  // Custom key prefix to namespace entries
  cache: kvCache(kv, { prefix: ["howl", "api", "cache"] }),
  rateLimitCache: kvCache(kv, { prefix: ["howl", "rl"] }),
});

import { tryCache, memoryCache, redisCache } from "@hushkey/howl/api/cache";

defineConfig({
  // Fast in-memory L1, shared Redis L2
  cache: tryCache(memoryCache({ maxSize: 500 }), redisCache(redis)),
});

import type { CacheAdapter } from "@hushkey/howl/api";

function pgCache(pool: Pool): CacheAdapter {
  return {
    async get(key) {
      const row = await pool.query(
        "SELECT value FROM cache WHERE key = $1 AND expires_at > NOW()",
        [key],
      );
      return row.rows[0]?.value ?? null;
    },
    async set(key, value, ttlSeconds) {
      await pool.query(
        "INSERT INTO cache (key, value, expires_at) VALUES ($1, $2, NOW() + $3 * interval '1 second')
         ON CONFLICT (key) DO UPDATE SET value = $2, expires_at = NOW() + $3 * interval '1 second'",
        [key, value, ttlSeconds],
      );
    },
    async delete(key) {
      await pool.query("DELETE FROM cache WHERE key = $1", [key]);
    },
  };
}
